// functions/api/auth.js

export async function onRequestPost(context) {
  const { request, env } = context;
  const url = new URL(request.url);
  const path = url.pathname;
  
  const body = await request.json();
  
  if (path.endsWith('/login')) {
    const { password } = body;
    if (!password) {
      return new Response(JSON.stringify({ error: 'Password is required' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    // Get passwords from D1 settings
    const sitePassword = await env.DB.prepare("SELECT value FROM settings WHERE key = 'site_password'").first("value");
    const adminPassword = await env.DB.prepare("SELECT value FROM settings WHERE key = 'admin_password'").first("value");

    if (password === adminPassword) {
      return new Response(JSON.stringify({ authenticated: true, role: 'admin' }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (password === sitePassword) {
      return new Response(JSON.stringify({ authenticated: true, role: 'user' }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    } else {
      return new Response(JSON.stringify({ authenticated: false, error: 'Incorrect password' }), {
        status: 401,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }

  if (path.endsWith('/change')) {
    const { role, currentPassword, newPassword } = body;
    if (!role || !currentPassword || !newPassword) {
      return new Response(JSON.stringify({ error: 'Missing fields' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    const key = role === 'admin' ? 'admin_password' : 'site_password';
    
    // Verify current password
    const existingPassword = await env.DB.prepare("SELECT value FROM settings WHERE key = ?").bind(key).first("value");
    
    if (currentPassword !== existingPassword) {
      return new Response(JSON.stringify({ error: 'Incorrect current password' }), {
        status: 401,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    // Update password
    await env.DB.prepare("UPDATE settings SET value = ? WHERE key = ?").bind(newPassword, key).run();

    return new Response(JSON.stringify({ success: true }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  return new Response(JSON.stringify({ error: 'Not found' }), {
    status: 404,
    headers: { 'Content-Type': 'application/json' }
  });
}
